class Solution:
    def shortestSubstrings(self, arr):
        n = len(arr)
        result = []
        for i in range(n):
            others = set()
            for j in range(n):
                if j == i:
                    continue
                s = arr[j]
                for l in range(len(s)):
                    for r in range(l+1, len(s)+1):
                        others.add(s[l:r])
            best = ''
            for length in range(1, len(arr[i]) + 1):
                candidates = []
                for start in range(len(arr[i]) - length + 1):
                    sub = arr[i][start:start+length]
                    if sub not in others:
                        candidates.append(sub)
                if candidates:
                    best = min(candidates)
                    break
            result.append(best)
        return result

