var shortestSubstrings = function(arr) {
    const n = arr.length;
    const result = [];
    for (let i = 0; i < n; i++) {
        const others = new Set();
        for (let j = 0; j < n; j++) {
            if (j === i) continue;
            const s = arr[j];
            for (let l = 0; l < s.length; l++)
                for (let r = l+1; r <= s.length; r++)
                    others.add(s.slice(l, r));
        }
        let best = '';
        for (let len = 1; len <= arr[i].length && best === ''; len++) {
            const candidates = [];
            for (let start = 0; start + len <= arr[i].length; start++) {
                const sub = arr[i].slice(start, start + len);
                if (!others.has(sub)) candidates.push(sub);
            }
            if (candidates.length > 0) {
                candidates.sort();
                best = candidates[0];
            }
        }
        result.push(best);
    }
    return result;
};
